   383	fn validate_atomic_compare_exchange_struct(
   384	    types: &crate::UniqueArena<crate::Type>,
   385	    members: &[crate::StructMember],
   386	    scalar_predicate: impl FnOnce(&crate::TypeInner) -> bool,
   387	) -> bool {
   388	    members.len() == 2
   389	        && members[0].name.as_deref() == Some("old_value")
   390	        && scalar_predicate(&types[members[0].ty].inner)
   391	        && members[1].name.as_deref() == Some("exchanged")
   392	        && types[members[1].ty].inner == crate::TypeInner::Scalar(crate::Scalar::BOOL)
   393	}
